+fn render_phase_chain(stages: &[DashboardSearchStage]) -> String {
+    if stages.is_empty() {
+        return "idle".to_owned();
+    }
+    let mut out = String::new();
+    for (idx, stage) in stages.iter().enumerate() {
+        if idx > 0 {
+            out.push_str(" -> ");
+        }
+        out.push_str(stage.label());
+    }
+    out
+}
